import { z } from 'zod';

export const E2E451ClientActionSchema = z.object({
  scenarioId: z.literal('e2e-451'),
  fixture: z.enum(['dense_dataset', 'empty_dataset', 'outlier_dataset', 'permission_denied']),
  action: z.enum(['render_chart', 'hover_or_focus_mark', 'export_or_drilldown', 'retry_data_load']),
  idempotencyKey: z.string().uuid(),
}).strict();

export const E2E451TrustedContextSchema = z.object({
  actorId: z.string().min(1),
  tenantId: z.string().min(1),
  role: z.enum(['owner','admin','member','viewer','system']),
  sessionId: z.string().min(1),
}).strict();

export const E2E451ResultSchema = z.object({
  status: z.enum(['passed','failed','denied','retryable_error']),
  httpStatus: z.union([z.literal(200), z.literal(202), z.literal(400), z.literal(403), z.literal(409), z.literal(422), z.literal(500)]),
  code: z.enum(['DATA_RENDERED', 'EMPTY_STATE', 'OUTLIER_HANDLED', 'EXPORT_READY', 'PERMISSION_DENIED']),
  userMessage: z.string().min(1),
  assertion: z.object({
    visibleState: z.literal('chart_or_table_assertion_visible'),
    scenarioTitle: z.literal('Recharts area gradient with theme variables'),
    redactedTelemetry: z.object({ event: z.literal('e2e.e2e-451.checked'), category: z.literal('recharts_mastery'), redacted: z.literal(true) }),
  }),
}).strict();

backend_solution:
// e2e-451: typed route for Recharts area gradient with theme variables
export async function handleE2E451(req, ctx) {
  const input = E2E451Schema.parse(await req.json());
  const authz = await ctx.authz.assertCan(input.actorId, 'recharts_mastery', input.tenantId);
  const result = await ctx.db.transaction(tx => ctx.flows.recharts_area_gradient_with_theme(tx, input, authz));
  ctx.metrics.observe('error_rate', result.metric);
  return Response.json(ResultSchema.parse(result));
}

frontend_solution:
export function E2E451Probe() {
  const [state, run] = useScenarioProbe('e2e-451', ['happy_path','denied','retry','rollback']);
  return <form aria-label='Recharts area gradient with theme variables' onSubmit={run}><output role='status'>{state.message}</output><button>Run</button></form>;
}

